using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Session> Sessions => Set<Session>();

    protected override void OnConfiguring(DbContextOptionsBuilder options)
    {
        options.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=...",
            "MyDatabase");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Fix 1: EF Core 9 changed the default discriminator property from
        // "Discriminator" to "$type". Existing documents use "Discriminator",
        // so we must explicitly preserve the old name.
        modelBuilder.Entity<Session>().HasDiscriminator<string>("Discriminator");

        // Fix 2: EF Core 9 changed `id` format from "EntityType|KeyValue" to
        // just "KeyValue". Existing documents use the old compound format,
        // so we must opt in to the old behavior.
        modelBuilder.Entity<Session>().HasRootDiscriminatorInJsonId(true);
    }
}

class Session
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

class CosmosQueryService
{
    // Fix 3: Cosmos DB provider in EF Core 9 no longer supports synchronous I/O.
    // All sync methods (ToList, SaveChanges, etc.) now throw.
    // Must use async equivalents.

    // BREAKS in EF Core 9:
    // List<Session> GetAll(CosmosDbContext db)
    //     => db.Sessions.ToList();

    // Fix — use async:
    async Task<List<Session>> GetAllAsync(CosmosDbContext db)
        => await db.Sessions.ToListAsync();

    // BREAKS in EF Core 9:
    // void Save(CosmosDbContext db) => db.SaveChanges();

    // Fix — use async:
    async Task SaveAsync(CosmosDbContext db) => await db.SaveChangesAsync();
}

